parameters.jsCode:
const { lead_name, email, phone, source, service, lead_score, lead_tier } = $json;

const tierEmoji = {
  'hot': '🔥',
  'warm': '🟡',
  'cold': '🔵'
};

const emoji = tierEmoji[lead_tier?.toLowerCase()] || '📋';
const timestamp = new Date().toLocaleString('en-US', { timeZone: 'America/Chicago' });

const message = [
  `${emoji} NEW LEAD`,
  ``,
  `${lead_name || 'Unknown'}`,
  `Phone: ${phone || 'N/A'}`,
  `Email: ${email || 'N/A'}`,
  `Source: ${source || 'Unknown'}`,
  `Service: ${service || 'Not specified'}`,
  `Score: ${lead_score ?? 'N/A'} (${lead_tier || 'unscored'})`,
  ``,
  `Respond within 5 minutes!`
].join('\n');

return [{ json: {
  alert_message: message,
  lead_name: lead_name || 'Unknown',
  lead_tier: lead_tier || 'unscored',
  timestamp
} }];

